ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS email text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS phone text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS address text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS city text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS state text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS country text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS zip text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS notes text; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS last_seen_at timestamp with time zone DEFAULT now(); CREATE TABLE IF NOT EXISTS public.support_tickets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL, subject text NOT NULL, description text NOT NULL, status text NOT NULL DEFAULT 'open', priority text NOT NULL DEFAULT 'medium', admin_notes text, resolved_at timestamp with time zone, created_at timestamp with time zone NOT NULL DEFAULT now(), updated_at timestamp with time zone NOT NULL DEFAULT now()); ALTER TABLE public.support_tickets ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users can manage own tickets" ON public.support_tickets FOR ALL TO authenticated USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid()); CREATE POLICY "Admins can manage all tickets" ON public.support_tickets FOR ALL TO authenticated USING (public.has_role(auth.uid(), 'admin'::app_role)) WITH CHECK (public.has_role(auth.uid(), 'admin'::app_role)); CREATE POLICY "Admins can read all profiles" ON public.profiles FOR SELECT TO authenticated USING (public.has_role(auth.uid(), 'admin'::app_role)); CREATE POLICY "Admins can read all subscriptions" ON public.subscriptions FOR SELECT TO authenticated USING (public.has_role(auth.uid(), 'admin'::app_role)); CREATE OR REPLACE FUNCTION public.handle_new_user() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN INSERT INTO public.profiles (id, display_name, email) VALUES (NEW.id, COALESCE(NEW.raw_user_meta_data->>'display_name', NEW.email), NEW.email); RETURN NEW; END; $$;